

(function(){
  // ==== Config ====

  window.onload = function() {
    const canvas = document.getElementById("heroTextCanvas");
    const ctx = canvas.getContext("2d");

    ctx.font = "48px Poppins";
    ctx.fillStyle = "#fff";
    ctx.textBaseline = "middle";
    ctx.fillText("Shun White — Portfolio", 30, 100);
}

  const PROT = {
    devtoolsThreshold: 160,        // px difference to suspect DevTools
    watermarkInterval: 7000,      // ms; how often to flip invisible watermark
    mutationChance: 0.12,         // chance to run each cycle (keeps light)
    overlayId: '__prot_overlay_v1'// overlay id if devtools detected
  };

  // ==== 1) Disable context menu & common shortcuts (non-lethal) ====
  document.addEventListener('contextmenu', e => e.preventDefault(), {passive:false});
  document.addEventListener('keydown', function(e){
    // block F12, Ctrl+Shift+I, Ctrl+Shift+C, Ctrl+U, Ctrl+S
    if (e.keyCode === 123) { e.preventDefault(); return false; } // F12
    if (e.ctrlKey && e.shiftKey && (e.key === 'I' || e.key === 'C' || e.key === 'J')) { e.preventDefault(); return false; }
    if (e.ctrlKey && (e.key === 'u' || e.key === 's')) { e.preventDefault(); return false; }
  }, {passive:false});

  function watermarkCycle(){
    if (Math.random() > PROT.mutationChance) return;
    try {
      const all = document.querySelectorAll('body *');
      if (!all || all.length < 6) return;
      const el = all[Math.floor(Math.random()*all.length)];
      const key = 'data-prot-'+Math.random().toString(36).slice(2,7);
      el.setAttribute(key, 'shun:' + Date.now().toString(36));
      // remove after a short delay to avoid layout issues
      setTimeout(()=> el.removeAttribute(key), 900 + Math.random()*1200);
    } catch(e){}
  }
  setInterval(watermarkCycle, PROT.watermarkInterval);

  function showQuickOverlay() {
    try {
      if (document.getElementById(PROT.overlayId)) return;
      const ov = document.createElement('div');
      ov.id = PROT.overlayId;
      ov.style.position = 'fixed';
      ov.style.inset = '0';
      ov.style.background = 'linear-gradient(90deg, rgba(139,0,0,0.08), rgba(0,0,0,0.6))';
      ov.style.zIndex = 99999998;
      ov.style.backdropFilter = 'blur(2px)';
      document.body.appendChild(ov);
      setTimeout(()=> {
        const el = document.getElementById(PROT.overlayId);
        if (el) el.remove();
      }, 900 + Math.random()*800);
    } catch(e){}
  }

  let lastWarn = 0;
  function detectDevTools() {
    try {

      const diff = Math.abs(window.outerWidth - window.innerWidth);
      const diffH = Math.abs(window.outerHeight - window.innerHeight);
      const now = Date.now();
      if ((diff > PROT.devtoolsThreshold || diffH > PROT.devtoolsThreshold) && now - lastWarn > 2500) {
        lastWarn = now;
        showQuickOverlay();
 
        try {
          const h = document.querySelector('.hero-headline');
          if (h) {
            const orig = h.textContent;
            h.textContent = orig.split('').reverse().join('');
            setTimeout(()=> { h.textContent = orig; }, 1200 + Math.random()*800);
          }
        } catch(e){}
      }
    } catch(e){}
  }
  setInterval(detectDevTools, 800);

  
  const __decoy_pool = (function(){
    // encoded garbage strings (base64) to look important
    const pool = [
      'VGhpcyBpcyBqdXN0IGEgZGVjb3kgc3RyaW5n',     // "This is just a decoy string"
      'U2h1ZmZsZSB0aGlzIG9uIGR1c3Q=',             // "Shuffle this on dust"
      'QXJ0aWZhY3Q6IFNodW4gV2hpdGU=',             // "Artifact: Shun White"
      'Q29weXJpZ2h0IOKAmTIwMjVTaHVu'              // looks like base64 garbage
    ];
    // simple decoder to be used rarely
    function decode(i){
      try { return atob(pool[i % pool.length]); } catch(e) { return ''; }
    }

    function uselessCrunch(n) {
      let s = 0;
      for (let i=0;i< (n%9 + 7); i++) {
        s ^= ((i + n) * 1337) >>> (i%3);
      }
      return s.toString(36);
    }
    return {decode, uselessCrunch};
  })();


  window.__SHUN_PROT = {
    stamp: Date.now(),
    rev: Math.random().toString(36).slice(2,8),
    decoy: __decoy_pool
  };

  if (location.protocol === 'file:') {
    try {
      const fov = document.createElement('div');
      fov.style.position='fixed';
      fov.style.inset='0';
      fov.style.background='linear-gradient(180deg, rgba(0,0,0,0.95), rgba(0,0,0,0.9))';
      fov.style.color='#FFD';
      fov.style.display='flex';
      fov.style.alignItems='center';
      fov.style.justifyContent='center';
      fov.style.zIndex=999999999;
      fov.innerHTML='<div style="text-align:center;max-width:720px;padding:20px;"><h2>Broken copy detected</h2><p style="opacity:.8">This is a protected copy — please visit the original site.</p></div>';
      document.addEventListener('DOMContentLoaded', ()=> document.body.appendChild(fov));
    } catch(e){}
  }

 
  setInterval(()=> {
    try {
      const links = document.querySelectorAll('link[rel="stylesheet"], script[src]');
      links.forEach((ln, idx) => {
        if (Math.random() < 0.06) { // keep it light
          const attr = ln.href ? 'href' : 'src';
          const val = ln[attr] || ln.getAttribute(attr);
          if (!val) return;
          const token = 'v=' + (Date.now() % 999999).toString(36);
          // append or replace query part
          if (val.indexOf('?v=') !== -1) ln.setAttribute(attr, val.replace(/\?v=\w+/, '?'+token));
          else ln.setAttribute(attr, val + (val.indexOf('?') === -1 ? '?' : '&') + token);
          // restore original after a short delay to avoid breaking display
          setTimeout(()=> {
            try { ln.setAttribute(attr, val); } catch(e){}
          }, 1200 + Math.random()*1400);
        }
      });
    } catch(e){}
  }, 4000 + Math.random()*3000);

})();

